def generate_payment_token(user_id: str, amount: Decimal, timestamp: str, secret_key: str) -> str:
    """
    Generate secure payment token to prevent tampering.
    """
    message = f"{user_id}:{amount}:{timestamp}"
    token = hmac.new(
        secret_key.encode(),
        message.encode(),
        hashlib.sha256
    ).hexdigest()
    return token


